MAP
  NAME "ky-imagery"
  STATUS ON
  SIZE 256 256
  # Kentucky extent in EPSG:3857 (Web Mercator)
  EXTENT -9968000 4368000 -9124000 4744000
  UNITS METERS

  OUTPUTFORMAT
    NAME png24
    DRIVER "AGG/PNG"
    MIMETYPE "image/png"
    IMAGEMODE RGB
    EXTENSION "png"
  END

  OUTPUTFORMAT
    NAME jpeg
    DRIVER "AGG/JPEG"
    MIMETYPE "image/jpeg"
    IMAGEMODE RGB
    EXTENSION "jpg"
  END

  IMAGETYPE PNG24
  IMAGECOLOR 255 255 255

  PROJECTION
    "init=epsg:3857"
  END

  WEB
    METADATA
      "ows_title"           "KyFromAbove 2024 Imagery"
      "ows_abstract"        "Kentucky aerial orthoimagery, 2024 Season 1 (3-inch resolution)"
      "ows_onlineresource"  "http://${PUBLIC_HOST}/mapserv"
      "ows_srs"             "EPSG:3857 EPSG:4326 EPSG:3089"
      "ows_enable_request"  "*"
      "F_enable_request"    "*"
      "wms_allow_getmap_without_styles" "true"
    END
  END

  CONFIG "MS_ERRORFILE" "stderr"
  CONFIG "MS_DEBUGLEVEL" "5"
  CONFIG "CPL_DEBUG" "ON"
  CONFIG "AWS_NO_SIGN_REQUEST" "YES"
  CONFIG "GDAL_CACHEMAX" "128"
  CONFIG "VSI_CACHE" "TRUE"
  CONFIG "VSI_CACHE_SIZE" "33554432"
  CONFIG "GDAL_DISABLE_READDIR_ON_OPEN" "TRUE"
  CONFIG "GDAL_HTTP_MULTIPLEX" "YES"
  CONFIG "GDAL_HTTP_VERSION" "2"
  CONFIG "GDAL_HTTP_MERGE_CONSECUTIVE_RANGES" "YES"
  CONFIG "CPL_VSIL_CURL_ALLOWED_EXTENSIONS" ".tif,.tiff"

  # OGC API / WFS footprint layer. Stored geometry is EPSG:3857 to match
  # incoming web-tile requests — no reprojection in the feature-query hot path.
  LAYER
    NAME "cog-extents"
    TYPE POLYGON
    STATUS ON
    TEMPLATE "unused"
    EXTENT -9968000 4368000 -9124000 4744000
    CONNECTIONTYPE POSTGIS
    CONNECTION "host=${DB_HOST} port=${DB_PORT} dbname=${DB_NAME} user=${DB_USER} password=${DB_PASS}"
    DATA "geom FROM cog_index USING UNIQUE id USING SRID=3857"
    PROJECTION
      "init=epsg:3857"
    END
    METADATA
      "ows_title"          "COG Tile Extents"
      "ows_abstract"       "KyFromAbove 2024 Season 1 COG footprints"
      "ows_srs"            "EPSG:3857 EPSG:4326"
      "gml_include_items"  "all"
      "gml_featureid"      "id"
      "gml_geometries"     "msGeometry"
      "gml_msGeometry_type" "multipolygon"
      "ows_enable_request" "*"
      "wfs_enable_request" "*"
      "F_enable_request"   "*"
      "ows_maxfeatures"    "10000"
    END
  END

  # Raster layer: TILEINDEX references the source-native EPSG:3089 tileindex
  # layer below. MapServer selects COGs in the raster CRS, then GDAL reads each
  # via /vsicurl/http://localhost:8001/... through the in-container nginx
  # proxy_cache layer shared by all FastCGI workers.
  LAYER
    NAME "ky-2024"
    TYPE RASTER
    STATUS ON
    TILEINDEX "cog-tileindex"
    TILEITEM "location"
    PROCESSING "BANDS=1,2,3"
    PROCESSING "RESAMPLE=AVERAGE"
    PROJECTION
      "init=epsg:3089"
    END
    METADATA
      "ows_title"    "KyFromAbove 2024 Season 1 (3 in)"
      "ows_abstract" "Kentucky high-resolution aerial imagery"
    END
  END

  LAYER
    NAME "cog-tileindex"
    TYPE POLYGON
    STATUS OFF
    EXTENT 3500000 3000000 6500000 4500000
    CONNECTIONTYPE POSTGIS
    CONNECTION "host=${DB_HOST} port=${DB_PORT} dbname=${DB_NAME} user=${DB_USER} password=${DB_PASS}"
    DATA "geom_3089 FROM cog_index USING UNIQUE id USING SRID=3089"
    PROJECTION
      "init=epsg:3089"
    END
  END

END
